[{"fieldname": "print_heading_template", "fieldtype": "Custom HTML", "options": "{# Get the "Registered Address" linked to the Company #}
{% set regd_address_name = frappe.db.get_value("Dynamic Link", {
"link_doctype": "Company",
"link_name": doc.company,
"parenttype": "Address",
}, "parent") %}

{% set regd_office = {} %}
{% if regd_address_name %}
{% set regd_office = frappe.get_doc("Address", regd_address_name) %}
{% endif %}

{% set logo_for_printing = frappe.db.get_value("Company", doc.company, "logo_for_printing") %}

<table style="width: 100%; margin-bottom: 1px;">
  <tr>
    <td style="width: 40%; vertical-align: top; padding: 0;">
      <div style="display: flex; align-items: flex-start;">
        {% if logo_for_printing %}
        <div style="margin-right: 2px;">
          <img src="{{ logo_for_printing }}" style="height: 50px; width: 50px; object-fit: scale-down;">
        </div>
        {% endif %}
        <div style="font-size: 10px; line-height: 1.4;">
          <div><strong>{{ doc.company }}</strong></div>
          {% if regd_office %}
          <div>Regd. Office: {{ regd_office.address_line1 or '' }}</div>
          <div>
            {{ regd_office.city or '' }}{% if regd_office.city %} - {% endif %}
            {{ regd_office.pincode or '' }}{% if regd_office.state %}, {{ regd_office.state }}{% endif %}
            {% if regd_office.country %}, {{ regd_office.country }}{% endif %}
          </div>
          {% if regd_office.phone %}
          <div>Phone: {{ regd_office.phone }}</div>
          {% endif %}
          {% endif %}
        </div>
      </div>
    </td>

    <td style="width: 20%; text-align: center; vertical-align: top;">
      <h2 style="margin: 0; font-size: 16px;">
        <strong>SALES ORDER</strong>
      </h2>
    </td>

    <td style="width: 2%;"></td>


    <td style="width: 38%; font-size: 10px; vertical-align: top; padding: 0; margin: 0;">
      <table style="width: 100%; border-collapse: collapse; border-spacing: 0;">
        <tr>
          <td style="padding: 0; font-size: inherit; line-height: 1.2;">
            <div style="margin: 0;">
              <strong>Order # & Dt:</strong> {{ doc.name }}&nbsp;&nbsp;<em>{{ doc.transaction_date or '' }}</em>
            </div>
          </td>

        </tr>

        {% if doc.delivery_date %}
        <tr>
          <td style="padding: 0; font-size: inherit; line-height: 1.2;">
            <div style="margin: 0;">
              <strong>Delivery Dt:</strong> <em>{{ doc.delivery_date }}</em>
            </div>
          </td>
        </tr>
        {% endif %}

        {% if doc.po_no and doc.po_date%}
        <tr>
          <td style="padding: 0; font-size: inherit; line-height: 1.2;">
            <div style="margin: 0;">
              <strong>PO. No. & Dt:</strong> {{ doc.po_no }}&nbsp;&nbsp;<em>{{ doc.po_date or '' }}</em>
            </div>
          </td>
        </tr>
        {% endif %}

        {% if doc.custom_delivery_terms %}
        <tr>
          <td style="padding: 0; font-size: inherit; line-height: 1.2;">
            <div style="margin: 0;">
              <strong>Terms of Delivery:</strong><em> {{ doc.custom_delivery_terms }}</em>
            </div>
          </td>
        </tr>
        {% endif %}

        {% if doc.custom_payment_terms %}
        <tr>
          <td style="padding: 0; font-size: inherit; line-height: 1.2;">
            <div style="margin: 0;">
              <strong>Terms of Payment:</strong><em> {{ doc.custom_payment_terms }}</em>
            </div>
          </td>
        </tr>
        {% endif %}
      </table>
    </td>
  </tr>
</table>"}, {"fieldtype": "Section Break", "label": ""}, {"fieldtype": "Column Break"}, {"fieldname": "_custom_html", "print_hide": 0, "label": "Custom HTML", "fieldtype": "HTML", "options": "<div style="font-size: 10px; line-height: 1.4;">
